import{_ as s,b as t,e as l,al as n}from"./chunks/framework.DrQIcdFj.js";(function(){try{var e=typeof window<"u"?window:typeof global<"u"?global:typeof globalThis<"u"?globalThis:typeof self<"u"?self:{};e.SENTRY_RELEASE={id:"abf23ae41d8e9798d1084c6d3fd2516340828177"};var i=new e.Error().stack;i&&(e._sentryDebugIds=e._sentryDebugIds||{},e._sentryDebugIds[i]="c4459076-0806-4c83-b707-1fb608c01d76",e._sentryDebugIdIdentifier="sentry-dbid-c4459076-0806-4c83-b707-1fb608c01d76")}catch{}})();const a="/CoreFront-EndConcepts/img/render.png",u=JSON.parse('{"title":"浏览器渲染机制:重绘与回流","description":"","frontmatter":{},"headers":[],"relativePath":"networkAndBrowsers/browser/renderingProcess.md","filePath":"networkAndBrowsers/browser/renderingProcess.md","lastUpdated":null}'),r={name:"networkAndBrowsers/browser/renderingProcess.md"};function d(e,i,o,c,g,h){return t(),l("div",null,[...i[0]||(i[0]=[n(`<h1 id="浏览器渲染机制-重绘与回流" tabindex="-1">浏览器渲染机制:重绘与回流 <a class="header-anchor" href="#浏览器渲染机制-重绘与回流" aria-label="Permalink to &quot;浏览器渲染机制:重绘与回流&quot;">​</a></h1><h2 id="_1-浏览器的渲染流程-rendering-process" tabindex="-1">1. 浏览器的渲染流程 (Rendering Process) <a class="header-anchor" href="#_1-浏览器的渲染流程-rendering-process" aria-label="Permalink to &quot;1. 浏览器的渲染流程 (Rendering Process)&quot;">​</a></h2><p>当浏览器从服务器下载完 HTML、CSS 和 JavaScript 等代码后，渲染引擎（如 Chrome 的 Blink，Safari 的 WebKit）会执行以下核心步骤：</p><ol><li><strong>解析 HTML，构建 DOM 树 (DOM Tree)</strong>： <ul><li>浏览器将 HTML 标签解析成树状的数据结构。DOM 树描述了网页的<strong>内容和骨架</strong>（包含所有的节点，哪怕是被 <code>display: none</code> 隐藏的节点）。</li></ul></li><li><strong>解析 CSS，构建 CSSOM 树 (CSSOM Tree)</strong>： <ul><li>浏览器将 CSS 样式表解析成树状结构，计算出每个节点的最终样式（Computed Style）。</li></ul></li><li><strong>合并，构建渲染树 (Render Tree)</strong>： <ul><li>将 DOM 树和 CSSOM 树结合起来。<strong>注意：渲染树只包含需要显示在屏幕上的节点</strong>。例如，<code>&lt;head&gt;</code> 标签、带有 <code>display: none</code> 样式的节点<strong>不会</strong>出现在渲染树中；但 <code>visibility: hidden</code> 的节点会存在（因为它占据空间）。</li></ul></li><li><strong>布局 / 回流 (Layout / Reflow)</strong>： <ul><li>有了渲染树（知道了有哪些元素以及它们的样式），浏览器需要计算出每个节点在屏幕上的<strong>确切几何信息（大小、位置）</strong>。这个过程就叫布局或回流。</li></ul></li><li><strong>绘制 / 重绘 (Paint / Repaint)</strong>： <ul><li>知道了元素的位置和大小，接下来就是把它们“画”出来。浏览器遍历渲染树，调用系统的图形 API（如 CPU 或 GPU），将每个节点的颜色、背景、边框、阴影、文字等<strong>视觉属性</strong>填充成屏幕上的像素。</li></ul></li><li><strong>合成 (Compositing)</strong>： <ul><li>现代浏览器为了提高效率，会将页面分成多个图层（Layers）分别绘制，最后再将这些图层按照正确的层叠顺序合并到一起，显示在屏幕上。</li></ul></li></ol><h2 id="_2-什么是回流-reflow-与重绘-repaint" tabindex="-1">2. 什么是回流 (Reflow) 与重绘 (Repaint)？ <a class="header-anchor" href="#_2-什么是回流-reflow-与重绘-repaint" aria-label="Permalink to &quot;2. 什么是回流 (Reflow) 与重绘 (Repaint)？&quot;">​</a></h2><p>在网页首次加载完成后，如果我们通过 JavaScript 操作 DOM 或者改变了 CSS 样式，浏览器可能需要重新执行上述的部分渲染步骤。</p><h3 id="_2-1-回流-reflow-——-牵一发而动全身" tabindex="-1">2.1 回流 (Reflow) —— “牵一发而动全身” <a class="header-anchor" href="#_2-1-回流-reflow-——-牵一发而动全身" aria-label="Permalink to &quot;2.1 回流 (Reflow) —— “牵一发而动全身”&quot;">​</a></h3><ul><li><strong>定义</strong>：当渲染树 (Render Tree) 中的部分或全部元素的<strong>几何属性（尺寸、位置、结构）<strong>发生改变时，浏览器必须</strong>重新计算</strong>这些元素及其受影响的父节点、子节点甚至兄弟节点的几何信息。这个重新计算布局的过程就是回流（也叫重排 Relayout）。</li><li><strong>代价</strong>：回流是<strong>非常昂贵</strong>的性能操作。因为元素的尺寸和位置变化，往往会导致整个页面的文档流发生错位，浏览器不得不重新计算大半个甚至整个页面的布局。</li><li><strong>触发回流的操作</strong>： <ul><li>添加或删除可见的 DOM 元素。</li><li>元素的位置发生变化（如 <code>top</code>, <code>left</code>, <code>margin</code>, <code>padding</code>）。</li><li>元素的尺寸发生变化（如 <code>width</code>, <code>height</code>, <code>border</code>）。</li><li>内容发生变化（如文本数量增加导致高度撑开，或者替换了不同尺寸的图片）。</li><li>浏览器窗口尺寸改变（resize）。</li><li><strong>读取某些特定的布局属性（极其重要，下文 FAQ 详述）</strong>。</li></ul></li></ul><h3 id="_2-2-重绘-repaint-——-换个马甲" tabindex="-1">2.2 重绘 (Repaint) —— “换个马甲” <a class="header-anchor" href="#_2-2-重绘-repaint-——-换个马甲" aria-label="Permalink to &quot;2.2 重绘 (Repaint) —— “换个马甲”&quot;">​</a></h3><ul><li><strong>定义</strong>：当元素的<strong>外观、视觉属性</strong>发生改变，但**完全没有改变它的几何属性（没有改变它在文档流中的位置和大小）**时，浏览器只需要把这个元素重新画一遍。这个过程就是重绘。</li><li><strong>代价</strong>：重绘的代价比回流<strong>小得多</strong>，因为它不需要重新计算布局。</li><li><strong>触发重绘的操作</strong>： <ul><li>改变 <code>color</code>, <code>background-color</code>。</li><li>改变 <code>visibility: hidden</code> (注意：<code>display: none</code> 会触发回流，因为元素消失且不再占位；而 <code>visibility: hidden</code> 只是不可见，仍占位，所以只触发重绘)。</li><li>改变 <code>box-shadow</code>, <code>border-radius</code>, <code>outline</code>。</li></ul></li></ul><p><strong>核心定律：回流必定会引起重绘，但重绘不一定会引起回流。</strong></p><h2 id="_3-浏览器的优化机制-渲染队列" tabindex="-1">3. 浏览器的优化机制：渲染队列 <a class="header-anchor" href="#_3-浏览器的优化机制-渲染队列" aria-label="Permalink to &quot;3. 浏览器的优化机制：渲染队列&quot;">​</a></h2><p>由于回流和重绘很消耗性能，浏览器其实非常聪明。它内置了一个<strong>渲染队列</strong>来进行批量优化。</p><p>如果你用 JS 连续修改了 3 个样式：</p><div class="language-js vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">div.style.width </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;100px&#39;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">div.style.height </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;100px&#39;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">div.style.marginTop </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;10px&#39;</span></span></code></pre></div><p>浏览器<strong>不会</strong>立刻执行 3 次回流。它会把这些修改操作放入一个队列中。当队列达到一定数量，或者过了一小段时间（通常是下一帧，约 16.6ms）后，浏览器会清空队列，<strong>将这多次修改合并成一次回流和重绘</strong>。</p><h2 id="_4-完整流程图" tabindex="-1">4. 完整流程图 <a class="header-anchor" href="#_4-完整流程图" aria-label="Permalink to &quot;4. 完整流程图&quot;">​</a></h2><p><img src="`+a+`" alt="Logo" data-zoomable="true"></p><h2 id="_5-常见问题-faq-与性能优化实战" tabindex="-1">5. 常见问题 (FAQ) 与性能优化实战 <a class="header-anchor" href="#_5-常见问题-faq-与性能优化实战" aria-label="Permalink to &quot;5. 常见问题 (FAQ) 与性能优化实战&quot;">​</a></h2><h3 id="_5-1-为什么-读取-某些属性会导致浏览器强制回流-性能杀手" tabindex="-1">5.1 为什么“读取”某些属性会导致浏览器强制回流（性能杀手）？ <a class="header-anchor" href="#_5-1-为什么-读取-某些属性会导致浏览器强制回流-性能杀手" aria-label="Permalink to &quot;5.1 为什么“读取”某些属性会导致浏览器强制回流（性能杀手）？&quot;">​</a></h3><p>浏览器有队列优化机制。但如果你在修改样式的同时，<strong>立刻去读取了元素的几何属性</strong>：</p><div class="language-js vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">div.style.width </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;100px&#39;</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> // 放入队列</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">console.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">log</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(div.offsetWidth) </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// 致命操作！</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">div.style.height </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;100px&#39;</span></span></code></pre></div><p>当执行到第二行 <code>div.offsetWidth</code> 时，浏览器为了给你返回最<strong>精确、最新</strong>的宽度值，它<strong>不得不立刻清空渲染队列，强行触发一次同步回流（Forced Synchronous Layout）</strong>，然后再把值给你。这直接打破了浏览器的优化机制。</p><p><strong>会触发强制同步回流的常见属性/方法</strong>：</p><ul><li><code>offsetTop</code>, <code>offsetLeft</code>, <code>offsetWidth</code>, <code>offsetHeight</code></li><li><code>scrollTop</code>, <code>scrollLeft</code>, <code>scrollWidth</code>, <code>scrollHeight</code></li><li><code>clientTop</code>, <code>clientLeft</code>, <code>clientWidth</code>, <code>clientHeight</code></li><li><code>getComputedStyle()</code></li><li><code>getBoundingClientRect()</code></li></ul><p><strong>优化建议</strong>：如果要在循环中读取这些值，<strong>一定要把它们缓存到局部变量中</strong>，不要在循环体内反复读取和写入。</p><h3 id="_5-2-如何尽量避免或减少回流与重绘" tabindex="-1">5.2 如何尽量避免或减少回流与重绘？ <a class="header-anchor" href="#_5-2-如何尽量避免或减少回流与重绘" aria-label="Permalink to &quot;5.2 如何尽量避免或减少回流与重绘？&quot;">​</a></h3><p>这是前端性能优化的重头戏：</p><ul><li><p><strong>CSS 层面</strong>：</p><ul><li><strong>合并样式修改</strong>：不要逐条修改 <code>style</code>，而是通过改变 <code>className</code> 或使用 <code>cssText</code> 一次性修改。</li><li><strong>避免使用 <code>table</code> 布局</strong>：表格中哪怕一个单元格的内容改变，都可能导致整个表格的重新计算。</li><li><strong>CSS3 硬件加速 (GPU 加速)</strong>：对于需要频繁做动画的元素，使用 <code>transform</code> (如 <code>translate</code>, <code>scale</code>) 和 <code>opacity</code>。<strong>这两个属性的改变，既不会触发回流，也不会触发重绘</strong>，它们是在最后的“合成 (Compositing)”阶段由 GPU 直接处理的，性能极高。</li><li>使用 <code>will-change: transform</code> 提前告诉浏览器该元素要做动画，浏览器会为其分配独立的图层（Layer），避免它的变化影响到其他节点。</li></ul></li><li><p><strong>JavaScript (DOM 操作) 层面</strong>：</p><ul><li><strong>离线操作 DOM</strong>：如果需要对 DOM 节点进行大量复杂的修改（如插入 1000 个 <code>&lt;li&gt;</code>）： <ol><li>先用 <code>display: none</code> 隐藏元素（1次回流）。</li><li>在内存中进行 1000 次修改（0次回流）。</li><li>再把 <code>display</code> 改回来（1次回流）。总共只发生 2 次回流。</li></ol></li><li><strong>使用 DocumentFragment</strong>：利用文档碎片 <code>document.createDocumentFragment()</code>，在内存中组装好一堆节点后，再用 <code>appendChild</code> 一次性插入到真实的 DOM 树中，这样只引发一次回流。</li><li><strong>脱离文档流</strong>：对于复杂的动画元素，将其设置为绝对定位 <code>position: absolute</code> 或 <code>fixed</code>，使其脱离文档流。这样它的变化就不会影响周围其他元素的布局了。</li></ul></li></ul>`,29)])])}const k=s(r,[["render",d]]);export{u as __pageData,k as default};
